class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        def is_prime(num):
            if num <= 1:
                return False
            if num <= 3:
                return True
            if num % 2 == 0 or num % 3 == 0:
                return False
            i = 5
            while i * i <= num:
                if num % i == 0 or num % (i + 2) == 0:
                    return False
                i += 6
            return True

        primes = [x for x in range(2, n) if is_prime(x)]
        result = []
        seen = set(primes)

        for prime in primes:
            complement = n - prime
            if complement in seen and is_prime(complement):
                result.append([min(prime, complement), max(prime, complement)])

        return sorted(result)

